const softDeleteMaintSchedule = `-- name: SoftDeleteMaintSchedule :execrows
UPDATE maintenance.maintenance_schedules
SET deleted_at = now()
WHERE id = $1 AND deleted_at IS NULL
`

func (q *Queries) SoftDeleteMaintSchedule(ctx context.Context, id uuid.UUID) (int64, error) {
	result, err := q.db.Exec(ctx, softDeleteMaintSchedule, id)
	if err != nil {
		return 0, err
	}
	return result.RowsAffected(), nil
}

